import{_ as e,a as t,b as n,c as i,d as s,e as d}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as l,o,c as r,a2 as p}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"IP Geolocation dan User Management","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/Other/ip-geolocation-and-user-management.md","filePath":"ms-MY/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),u={name:"ms-MY/Other/ip-geolocation-and-user-management.md"};function c(m,a,g,h,k,b){return o(),r("div",null,[...a[0]||(a[0]=[p('<h1 id="ip-geolocation-dan-user-management" tabindex="-1">IP Geolocation dan User Management <a class="header-anchor" href="#ip-geolocation-dan-user-management" aria-label="Permalink to &quot;IP Geolocation dan User Management&quot;">​</a></h1><p>IP geolocation menukar IP addresses dalam uploader records, login devices dan logs seumpamanya kepada locations anggaran.</p><p>Selepas dikonfigurasi, admin panel boleh menunjukkan asal upload dan access dengan lebih jelas. User Management juga membolehkan anda block atau restore upload access untuk IP addresses yang mencurigakan.</p><h2 id="di-mana-untuk-configure" tabindex="-1">Di Mana Untuk Configure <a class="header-anchor" href="#di-mana-untuk-configure" aria-label="Permalink to &quot;Di Mana Untuk Configure&quot;">​</a></h2><p>Buka:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; IP Geolocation</span></span></code></pre></div><p><img src="'+e+`" alt="IP geolocation" loading="lazy"></p><h2 id="available-settings" tabindex="-1">Available Settings <a class="header-anchor" href="#available-settings" aria-label="Permalink to &quot;Available Settings&quot;">​</a></h2><p>Flow IP geolocation baharu menyokong beberapa sources, bukan bergantung kepada satu map service sahaja.</p><table tabindex="0"><thead><tr><th>Setting</th><th>Purpose</th></tr></thead><tbody><tr><td>IP geolocation language</td><td>Memilih display language, seperti English, Simplified Chinese, Japanese, French dan lain-lain.</td></tr><tr><td>MaxMind Account ID</td><td>MaxMind account ID untuk MaxMind GeoLite Web Service.</td></tr><tr><td>MaxMind License Key</td><td>MaxMind License Key.</td></tr><tr><td>Tencent Map Key</td><td>Tencent Location Service key. Berguna untuk Chinese addresses dan mainland China IPs.</td></tr><tr><td>ipapi Key</td><td>APILayer ipapi key. Menyokong multilingual IP geolocation.</td></tr></tbody></table><p>Isi hanya services yang anda perlukan. Anda tidak perlu configure semua field.</p><p>Jika tiada key diberi, ImgBed masih cuba built-in free sources, tetapi stability, language support dan precision mungkin lebih rendah daripada service yang anda configure sendiri.</p><h2 id="recommended-choices" tabindex="-1">Recommended Choices <a class="header-anchor" href="#recommended-choices" aria-label="Permalink to &quot;Recommended Choices&quot;">​</a></h2><p>Jika anda terutama memerlukan Chinese addresses:</p><ol><li>Tetapkan IP geolocation language kepada Simplified Chinese.</li><li>Configure Tencent Map Key.</li><li>Optional: tambah MaxMind atau ipapi sebagai fallback sources.</li></ol><p>Jika anda terutama memerlukan English atau multilingual addresses:</p><ol><li>Pilih language yang diperlukan.</li><li>Configure MaxMind Account ID dan License Key.</li><li>Tambah ipapi Key jika mahu multilingual results yang lebih baik.</li></ol><h2 id="maxmind-setup" tabindex="-1">MaxMind Setup <a class="header-anchor" href="#maxmind-setup" aria-label="Permalink to &quot;MaxMind Setup&quot;">​</a></h2><p>MaxMind memerlukan:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>Dapatkan account ID dalam MaxMind dashboard dan generate License Key dari License Keys page.</p><p><img src="`+t+'" alt="MaxMind key config" loading="lazy"></p><p>Selepas dijana, paste Account ID dan License Key ke ImgBed dan save.</p><p>Free plan MaxMind sesuai untuk everyday use, tetapi ada request limits. Jika quota exceeded, ImgBed terus mencuba sources lain yang available.</p><h2 id="ipapi-setup" tabindex="-1">ipapi Setup <a class="header-anchor" href="#ipapi-setup" aria-label="Permalink to &quot;ipapi Setup&quot;">​</a></h2><p>ipapi menggunakan APILayer API Key.</p><p>Buka ipapi console dan copy API Key yang ditunjukkan.</p><p><img src="'+n+'" alt="ipapi config" loading="lazy"></p><p>Paste ke field <code>ipapi Key</code> dalam ImgBed dan save.</p><p>ipapi menyokong multilingual IP geolocation dan berguna apabila anda mahu addresses dipaparkan dalam selected language. Free plan juga ada request limits. Jika quota habis, ImgBed terus mencuba sources lain yang available.</p><h2 id="tencent-map-key-setup" tabindex="-1">Tencent Map Key Setup <a class="header-anchor" href="#tencent-map-key-setup" aria-label="Permalink to &quot;Tencent Map Key Setup&quot;">​</a></h2><p>Tencent Map Key berguna untuk Chinese addresses, terutama mainland China IPs.</p><p>Semasa mencipta key dalam Tencent Location Service, enable:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>Selepas creation, paste key ke <code>Tencent Map Key</code> dan save.</p><p>Jika anda hanya perlukan basic Chinese IP geolocation, Tencent Map Key sudah cukup untuk bermula.</p><h2 id="apa-yang-perlu-disemak-dalam-user-management" tabindex="-1">Apa Yang Perlu Disemak Dalam User Management <a class="header-anchor" href="#apa-yang-perlu-disemak-dalam-user-management" aria-label="Permalink to &quot;Apa Yang Perlu Disemak Dalam User Management&quot;">​</a></h2><p>User Management tersedia dari bahagian atas admin panel.</p><p><img src="'+i+'" alt="User management" loading="lazy"></p><p>User Management memaparkan upload activity mengikut IP:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>IP source</td><td>Uploader source IP.</td></tr><tr><td>Address</td><td>Location anggaran yang resolved daripada IP.</td></tr><tr><td>Total upload size</td><td>Jumlah file size yang di-upload oleh IP ini.</td></tr><tr><td>Upload count</td><td>Bilangan uploads daripada IP ini.</td></tr><tr><td>Upload allowed</td><td>On bermaksud uploads dibenarkan. Off bermaksud uploads diblock.</td></tr></tbody></table><p>Klik arrow di kiri untuk expand list files yang di-upload oleh IP tersebut.</p><p>File list menunjukkan file name, preview, file size, moderation result, file status dan upload time. Jika uploads kelihatan mencurigakan, expand IP dahulu, review files, kemudian tentukan sama ada perlu block uploads seterusnya.</p><p>Jika IP mencurigakan, matikan <code>Upload allowed</code>. Future uploads daripada IP tersebut akan diblock.</p><h2 id="search-sort-dan-advanced-filters" tabindex="-1">Search, Sort dan Advanced Filters <a class="header-anchor" href="#search-sort-dan-advanced-filters" aria-label="Permalink to &quot;Search, Sort dan Advanced Filters&quot;">​</a></h2><p>Di bahagian atas User Management, search menggunakan IP source atau address.</p><p>Sort mengikut time, upload count atau total upload size untuk mencari recent uploaders, high-frequency uploaders atau high-usage IPs.</p><p>Untuk siasatan lebih mendalam, buka advanced filters.</p><p><img src="'+s+'" alt="Advanced filters" loading="lazy"></p><p>Advanced filters menyokong:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Usage</th></tr></thead><tbody><tr><td>Time range</td><td>Menunjukkan IPs yang upload files dalam tempoh dipilih.</td></tr><tr><td>Access status</td><td>Filter mengikut normal, blocked dan states seumpamanya.</td></tr><tr><td>Allow/block list</td><td>Filter mengikut allowlist, blocklist atau unset.</td></tr><tr><td>File type</td><td>Menunjukkan IPs yang upload images, videos, audio, documents, code atau other files.</td></tr><tr><td>File size</td><td>Filter mengikut uploaded file size range.</td></tr><tr><td>Age rating</td><td>Filter mengikut unset, General, R12+, R16+, R18 dan ratings seumpamanya.</td></tr><tr><td>File status</td><td>Filter mengikut current file status untuk menyiasat abnormal files.</td></tr></tbody></table><p>Klik <code>Apply Filters</code> untuk apply. Gunakan <code>Reset</code> untuk kembali kepada semua data.</p><h2 id="mobile-view" tabindex="-1">Mobile View <a class="header-anchor" href="#mobile-view" aria-label="Permalink to &quot;Mobile View&quot;">​</a></h2><p>Pada mobile, User Management bertukar kepada card layout.</p><p><img src="'+d+`" alt="Mobile user management" loading="lazy"></p><p>Setiap card menunjukkan IP, address, total upload size, upload count dan upload allowed switch. Anda boleh manage users tanpa horizontal table scrolling.</p><h2 id="jika-location-kelihatan-salah" tabindex="-1">Jika Location Kelihatan Salah <a class="header-anchor" href="#jika-location-kelihatan-salah" aria-label="Permalink to &quot;Jika Location Kelihatan Salah&quot;">​</a></h2><p>IP geolocation adalah anggaran. Ia bukan street address yang tepat.</p><p>Jika user berada di belakang proxy, data center, cloud server atau cross-border network, location yang dipaparkan mungkin berbeza daripada location sebenar.</p><p>Gunakan feature ini untuk memahami rough origin, mencari abnormal uploads dan membantu blocking decisions. Jangan anggap ia sebagai precise tracking.</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>Meaning</th></tr></thead><tbody><tr><td>Address kosong</td><td>IP mungkin belum resolved, atau current source temporarily unavailable.</td></tr><tr><td>Address language salah</td><td>Semak IP geolocation language dan sama ada source yang menyokong language itu telah dikonfigurasi.</td></tr><tr><td>Address menunjukkan data center</td><td>Banyak proxies, cloud servers dan crawlers muncul sebagai data center atau ISP addresses.</td></tr><tr><td>Upload count tinggi</td><td>Review IP ini dengan teliti dan block uploads jika perlu.</td></tr><tr><td>Total upload size besar</td><td>Sort atau filter, expand IP dan inspect specific files.</td></tr><tr><td>Perlu restore selepas blocking</td><td>Hidupkan semula <code>Upload allowed</code>.</td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Buka IP Geolocation dalam Other Settings</span></span>
<span class="line"><span>-&gt; Pilih IP geolocation language</span></span>
<span class="line"><span>-&gt; Isi MaxMind, Tencent Map atau ipapi credentials jika perlu</span></span>
<span class="line"><span>-&gt; Save settings</span></span>
<span class="line"><span>-&gt; Buka User Management</span></span>
<span class="line"><span>-&gt; Review IP source, address, total upload size dan upload count</span></span>
<span class="line"><span>-&gt; Gunakan search, sort atau advanced filters untuk mencari abnormal IPs</span></span>
<span class="line"><span>-&gt; Allow atau block uploads mengikut keperluan</span></span></code></pre></div>`,64)])])}const M=l(u,[["render",c]]);export{f as __pageData,M as default};
